import React, { Component } from 'react';
import { NavLink, withRouter } from 'react-router-dom';
import PropTypes from 'prop-types';
import $ from 'jquery';
import s from '../Intro.module.scss';

class IntroductionLayout extends Component {

    constructor(props) {
        super(props);
        this.state = {

        };
    }

    componentDidMount() {
        const { pathname } = this.props.location;
        if (pathname == "/login" || pathname == "/signup") {
            $('#ap_mn_nav').css('background', 'rgba(255,255,255,0)');
        }
    }

    render() {
        return (
            <nav className={s['nav']} id="ap_mn_nav">
                <div className={[s['nav__inner'], "g-width"].join(' ')}>
                    <div className={s['nav__logo']}>
                        <h5><NavLink to="/">{process.env.REACT_APP_APPNAME}</NavLink></h5>
                    </div>
                    <div className={s['nav__list']}>
                        <ul>
                            {/* <li><NavLink to="" activeClassName={s['nav__list--active']}>Features</NavLink></li> */}
                            <li><NavLink to="/discover" activeClassName={s['nav__list--active']}>Discover</NavLink></li>
                            <li><NavLink to="/login" activeClassName={s['nav__list--active']}>Login /  </NavLink><NavLink to="/signup" activeClassName={s['nav__list--active']}>Signup</NavLink></li>
                        </ul>
                    </div>
                </div>
            </nav>
        )
    }
}

export default withRouter(IntroductionLayout);
